module top_module(
    input clk,
    input rst,
    input [3:0] a,
    input [3:0] b,
    input cin,
    output reg [3:0] sum,  // Changed to reg to allow assignments in always block
    output reg cout        // Changed to reg to allow assignments in always block
);reg [3:0] sum_reg;
wire [4:0] sum_wire;
wire overflow;

  wire _n01 = a + b[0] ^ cin[0];
  wire _c01 = a + b[0] & cin[0];
  wire _n02 = a + b[1] ^ cin[1] ^ _c01;
  wire _c02 = (a + b[1] & cin[1]) | (a + b[1] & _c01) | (cin[1] & _c01);
  wire _n03 = a + b[2] ^ cin[2] ^ _c02;
  wire _c03 = (a + b[2] & cin[2]) | (a + b[2] & _c02) | (cin[2] & _c02);
  wire _n04 = a + b[3] ^ cin[3] ^ _c03;
  wire _c04 = (a + b[3] & cin[3]) | (a + b[3] & _c03) | (cin[3] & _c03);
  assign sum_wire = {_n01, _n02, _n03, _n04};
assign overflow = sum_wire[4];

always @(posedge clk) begin
    if (rst) begin
        sum_reg <= 0;
        cout <= 0;
    end else begin
        sum_reg <= sum_wire[3:0];
        cout <= overflow;
    end
end

assign sum = sum_reg;

endmodule
